"use client";

import { useState } from "react";
import { BRANCHES, LINKS, SERVICES_DD } from "../data/siteData";

export default function HeroForm() {
  const [done, setDone] = useState(false);
  const [name, setName] = useState("");
  const [mobile, setMobile] = useState("");
  const [branch, setBranch] = useState("");
  const [service, setService] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (name && mobile && branch && service) {
      setDone(true);
    }
  };

  return (
    <div className="hform">
      <div className="hform-head">
        <h3>Get a call back</h3>
        <span className="chip chip-static">
          <i className="dot" /> Team responds quickly
        </span>
      </div>
      {done ? (
        <div className="form-done">
          <span>✓</span>
          <p>
            Thank you! Our care team will call you back shortly. For
            emergencies, please call us directly.
          </p>
        </div>
      ) : (
        <form onSubmit={handleSubmit}>
          <label>
            <input 
              placeholder="Patient / Parent name" 
              value={name} 
              onChange={(e) => setName(e.target.value)} 
              required 
            />
          </label>
          <label>
            <input 
              placeholder="Mobile number" 
              type="tel" 
              value={mobile} 
              onChange={(e) => setMobile(e.target.value)} 
              required 
            />
          </label>
          <label>
            <select value={branch} onChange={(e) => setBranch(e.target.value)} required>
              <option value="" disabled>Preferred branch</option>
              {BRANCHES.map((b) => <option key={b.short} value={b.short}>{b.short}</option>)}
            </select>
          </label>
          <label>
            <select value={service} onChange={(e) => setService(e.target.value)} required>
              <option value="" disabled>Service needed</option>
              {SERVICES_DD.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
          </label>
          <button type="submit" className="btn btn-pink btn-full">
            Request a Call Back <span className="arr">↗</span>
          </button>
          <p className="hform-note">
            For emergencies, call <a href={LINKS.phone}>+91 00000 00000</a> —
            available 24/7.
          </p>
        </form>
      )}
    </div>
  );
}
