"use client";

import { useState } from "react";
import { BRANCHES, IMG, SERVICES_DD } from "../data/siteData";
import { Img, Pill, Reveal } from "./common";

export default function BookingSection() {
  const [sent, setSent] = useState(false);
  const [name, setName] = useState("");
  const [mobile, setMobile] = useState("");
  const [branch, setBranch] = useState("");
  const [service, setService] = useState("");
  const [concern, setConcern] = useState("");
  const [message, setMessage] = useState("");

  const handleBookingSubmit = (e) => {
    e.preventDefault();
    if (name && mobile && branch && service && concern) {
      setSent(true);
    }
  };

  return (
        <section className="section" id="book">
          <div className="contact">
            <Reveal>
              <Pill>Appointments</Pill>
              <h2>Book an appointment</h2>
              <p className="sec-note mt-14">
                Please fill in your details. Our team will call you back
                shortly.
              </p>
              <ul className="contact-list">
                <li><i>📞</i> +91 77083 18222</li>
                <li><i>📍</i> Madurai • Southwing Madurai • Dindigul • Thanjavur</li>
                <li><i>🕐</i> Emergency, NICU &amp; PICU — 24/7</li>
              </ul>
              <Img src={IMG.advancedNICU25} alt="Advanced NICU care at Rio" grad={2} className="contact-img" />
            </Reveal>
            <Reveal delay={120}>
              <div className="form-card">
                <h3>Request a call back</h3>
                {sent ? (
                  <div className="form-done">
                    <span>✓</span>
                    <p>
                      Thank you! Your request is noted — our team will call you
                      back shortly. (Connect this form to your CRM or WhatsApp
                      to receive submissions.)
                    </p>
                  </div>
                ) : (
                  <form onSubmit={handleBookingSubmit}>
                    <div className="form-row">
                      <label>
                        <input 
                          placeholder="Patient / Parent name" 
                          value={name} 
                          onChange={(e) => setName(e.target.value)} 
                          required 
                        />
                      </label>
                      <label>
                        <input 
                          placeholder="Mobile number" 
                          type="tel" 
                          value={mobile} 
                          onChange={(e) => setMobile(e.target.value)} 
                          required 
                        />
                      </label>
                    </div>
                    <div className="form-row form-row-full">
                      <label>
                        <select value={branch} onChange={(e) => setBranch(e.target.value)} required>
                          <option value="" disabled>Location / branch preference</option>
                          {BRANCHES.map((b) => <option key={b.short} value={b.short}>{b.short}</option>)}
                        </select>
                      </label>
                      <label>
                        <select value={service} onChange={(e) => setService(e.target.value)} required>
                          <option value="" disabled>Service needed</option>
                          {SERVICES_DD.map((s) => <option key={s} value={s}>{s}</option>)}
                        </select>
                      </label>
                    </div>
                    <div className="form-row">
                      <label>
                        <select value={concern} onChange={(e) => setConcern(e.target.value)} required>
                          <option value="" disabled>Concern is for…</option>
                          <option value="Child">Child</option>
                          <option value="Mother">Mother</option>
                          <option value="Newborn">Newborn</option>
                        </select>
                      </label>
                    </div>
                    <label className="lbl-full">
                      <textarea 
                        placeholder="Message (optional)" 
                        rows={3} 
                        value={message} 
                        onChange={(e) => setMessage(e.target.value)} 
                      />
                    </label>
                    <button type="submit" className="btn btn-pink btn-full">
                      Request a Call Back <span className="arr">↗</span>
                    </button>
                  </form>
                )}
              </div>
            </Reveal>
          </div>
        </section>
  );
};
